sql:
SELECT song_id, COUNT(comment_id) AS total_comments
FROM song_comments
GROUP BY song_id;

SELECT song_id, comment_text, comment_date
FROM song_comments
WHERE comment_date = '2023-05-01' AND song_id = 0;

SELECT COUNT(DISTINCT producer_id) AS unique_primary_producers
FROM song_producers
WHERE is_primary = 1;

